class Solution:
    def findMinFibonacciNumbers(self, k: int) -> int:
        # Build Fibonacci sequence up to k
        fibs = [1, 1]
        while fibs[-1] < k:
            fibs.append(fibs[-1] + fibs[-2])
        count = 0
        while k > 0:
            # Find largest fib <= k by linear scan
            f = 1
            for x in fibs:
                if x <= k:
                    f = x
                else:
                    break
            k -= f
            count += 1
        return count

