class Solution:
    def findMinFibonacciNumbers(self, k: int) -> int:
        import bisect
        fibs = [1, 1]
        while fibs[-1] < k:
            fibs.append(fibs[-1] + fibs[-2])
        count = 0
        while k > 0:
            idx = bisect.bisect_right(fibs, k) - 1
            k -= fibs[idx]
            count += 1
        return count

