var findMinFibonacciNumbers = function(k) {
    const fibs = [1, 1];
    while (fibs[fibs.length - 1] < k) {
        const n = fibs.length;
        fibs.push(fibs[n-1] + fibs[n-2]);
    }
    let count = 0;
    while (k > 0) {
        let idx = fibs.length - 1;
        while (fibs[idx] > k) idx--;
        k -= fibs[idx];
        count++;
    }
    return count;
};
